# Reproject the main megastudy's sampling quotas to the benchmark's reduced
# target sample. The benchmark drops the 4 interactive conditions, so the human
# target is N = 18,000 (16 interventions x 1,000 + control x 2,000) rather than
# the main megastudy's N = 22,000.
#
# The Census-derived demographic proportions are identical regardless of N; only
# the absolute cell counts scale. We therefore recover the proportions from the
# main study's quota table (trust_climate_scientists/data/quotas.csv, itself
# generated by R/quotas.R from the 2024 Census Bureau Population Estimates) and
# re-apply the same projection formula with N = 18,000.

library(tidyverse)

quotas_main <- read_csv(
  "~/git/trust_climate_scientists/data/quotas.csv",
  show_col_types = FALSE
)

parse_n <- function(x) as.numeric(str_extract(x, "^[0-9]+"))

N <- 18000

quotas_18000 <- quotas_main |>
  mutate(
    nt = parse_n(Total),
    nm = parse_n(Male),
    nf = parse_n(Female)
  ) |>
  group_by(Variable) |>
  mutate(
    pct_total    = nt / sum(nt),
    share_male   = nm / nt,
    share_female = nf / nt,
    cell         = round(pct_total * N),
    n_male       = round(share_male * cell),
    n_female     = round(share_female * cell)
  ) |>
  ungroup() |>
  transmute(
    Variable,
    Category,
    Total  = sprintf("%d (%.1f%%)", cell,     pct_total * 100),
    Male   = sprintf("%d (%.1f%%)", n_male,   share_male * 100),
    Female = sprintf("%d (%.1f%%)", n_female, share_female * 100)
  )

write_csv(quotas_18000, here::here("data/quotas_18000.csv"))
